18	/**
19	 * Utility class for Excel file operations.
20	 * Provides methods for appending sheets and data rows to Excel files.
21	 *
22	 * @author summer
23	 * @version 1.00
24	 * @date 2026/3/4
25	 */
26	public class ExcelUtil {
27	    private static final Logger logger = LoggerFactory.getLogger(ExcelUtil.class);
28	
29	    private static final Set<String> INVALID_VALUES = Set.of(
30	            "NA", "N/A", "NULL", "NIL", "NONE", "NAN",
31	            "#N/A", "#NULL!", "#REF!", "#DIV/0!", "#VALUE!", "#NAME?", "#NUM!", "#ERROR!",
32	            "-", "--", "—", "N.A.", "N.A"
33	    );
34	
35	    /**
36	     * Appends rows from 0 to endRowIndex of the specified sheet (by name) in source file to target file.
37	     * Creates target file if it doesn't exist; appends to existing sheet without overwriting.
38	     *
39	     * @param sourceFilePath source file path
40	     * @param targetFilePath target file path (creates if not exists)
41	     * @param sheetName      sheet name to copy
42	     * @param endRowIndex    end row index (0-based, inclusive)
43	     */
44	    public static void appendSheet(String sourceFilePath, String targetFilePath,
45	                                   String sheetName, int endRowIndex) throws IOException {
46	        if (endRowIndex < 0) throw new IllegalArgumentException("endRowIndex cannot be negative");
47	
48	        // 1. Read source file and locate sheet
49	        try (FileInputStream srcFis = new FileInputStream(sourceFilePath);
50	             Workbook sourceWorkbook = WorkbookFactory.create(srcFis)) {
51	
52	            Sheet sourceSheet = sourceWorkbook.getSheet(sheetName);
53	            if (sourceSheet == null) {
54	                throw new IllegalArgumentException("Sheet not found: " + sheetName
55	                        + ", available sheets: " + getSheetNames(sourceWorkbook));
56	            }
57	
58	            // 2. Load or create target workbook
59	            Workbook targetWorkbook = loadOrCreate(targetFilePath);
60	
61	            // 3. Target file must not have a sheet with the same name
62	            if (targetWorkbook.getSheet(sheetName) != null) {
63	                targetWorkbook.close();
64	                throw new IllegalArgumentException("Target file already has sheet: " + sheetName);
65	            }
66	
67	            // 4. Append sheet
68	            copySheetRows(sourceSheet, targetWorkbook, sheetName, endRowIndex);
69	
70	            // 5. Write back to target file
71	            try (FileOutputStream fos = new FileOutputStream(targetFilePath)) {
72	                targetWorkbook.write(fos);
73	            }
74	            targetWorkbook.close();
75	
76	            logger.debug("Sheet appended | sheet={}, rows=0-{}, target={}", sheetName, endRowIndex, targetFilePath);
77	        }
78	    }
79	
80	    /**
81	     * Appends rows from 0 to endRowIndex of the specified sheet (by index) in source file to target file.
82	     *
83	     * @param sourceFilePath source file path
84	     * @param targetFilePath target file path (creates if not exists)
85	     * @param sheetIndex     sheet index (0-based)
86	     * @param endRowIndex    end row index (0-based, inclusive)
87	     */
88	    public static void appendSheet(String sourceFilePath, String targetFilePath,
89	                                   int sheetIndex, int endRowIndex) throws IOException {
90	        if (endRowIndex < 0) throw new IllegalArgumentException("endRowIndex cannot be negative");
91	
92	        try (FileInputStream srcFis = new FileInputStream(sourceFilePath);
93	             Workbook sourceWorkbook = WorkbookFactory.create(srcFis)) {
94	
95	            if (sheetIndex < 0 || sheetIndex >= sourceWorkbook.getNumberOfSheets()) {
96	                throw new IllegalArgumentException("sheetIndex out of bounds: " + sheetIndex
97	                        + ", total sheets: " + sourceWorkbook.getNumberOfSheets());
98	            }
99	
100	            Sheet sourceSheet = sourceWorkbook.getSheetAt(sheetIndex);
101	            appendSheet(sourceFilePath, targetFilePath, sourceSheet.getSheetName(), endRowIndex);
102	        }
103	    }
104	
105	    /**
106	     * Copies an entire sheet from source file to target file as-is.
107	     * Preserves all styles, column widths, merged regions, and formulas.
108	     * Unlike appendSheet which copies rows 0 to endRowIndex, this copies the entire sheet.
109	     *
110	     * @param sourceFilePath source Excel file path
111	     * @param targetFilePath target Excel file path (creates if not exists)
112	     * @param sheetName      sheet name to copy entirely
113	     */
114	    public static void copyEntireSheet(String sourceFilePath, String targetFilePath,
115	                                       String sheetName) throws IOException {
116	        try (FileInputStream srcFis = new FileInputStream(sourceFilePath);
117	             Workbook sourceWorkbook = WorkbookFactory.create(srcFis)) {
118	
119	            Sheet sourceSheet = sourceWorkbook.getSheet(sheetName);
120	            if (sourceSheet == null) {
121	                throw new IllegalArgumentException("Sheet not found: " + sheetName
122	                        + ", available sheets: " + getSheetNames(sourceWorkbook));
123	            }
124	
125	            Workbook targetWorkbook = loadOrCreate(targetFilePath);
126	
127	            if (targetWorkbook.getSheet(sheetName) != null) {
128	                targetWorkbook.close();
129	                throw new IllegalArgumentException("Target file already has sheet: " + sheetName);
130	            }
131	
132	            copySheetRows(sourceSheet, targetWorkbook, sheetName, sourceSheet.getLastRowNum());
133	
134	            try (FileOutputStream fos = new FileOutputStream(targetFilePath)) {
135	                targetWorkbook.write(fos);
136	            }
137	            targetWorkbook.close();
138	
139	            logger.debug("Entire sheet copied | sheet={}, rows=0-{}, target={}",
140	                    sheetName, sourceSheet.getLastRowNum(), targetFilePath);
141	        }
142	    }
143	
144	    /**
145	     * Appends data rows to an existing sheet in target file.
146	     *
147	     * @param orgFilePath   source file path (for getting style template)
148	     * @param targetFilePath target file path
149	     * @param sheetName     target sheet name
150	     * @param startRowIndex row index to start writing (typically header index)
151	     * @param rows          data rows to append
152	     */
153	    public static void appendDataRowsByPoi(
154	            String orgFilePath,
155	            String targetFilePath,
156	                                     String sheetName,
157	                                     int startRowIndex,
158	                                     List<Map<Integer, Object>> rows) throws IOException {
159	        // Get style template row from source file
160	        Row templateRow = null;
161	        try (FileInputStream srcFis = new FileInputStream(orgFilePath);
162	             Workbook srcWb = WorkbookFactory.create(srcFis)) {
163	            Sheet srcSheet = srcWb.getSheet(sheetName);
164	            if (srcSheet != null) {
165	                templateRow = srcSheet.getRow(startRowIndex);
166	            }
167	        }
168	
169	        // Open target file for appending
170	        File file = new File(targetFilePath);
171	        Workbook workbook;
172	        try (FileInputStream fis = new FileInputStream(file)) {
173	            workbook = WorkbookFactory.create(fis);
174	        }
175	        try {
176	
177	        Sheet sheet = workbook.getSheet(sheetName);
178	        Map<Integer, CellStyle> styleCache = new HashMap<>();
179	        final Row finalTemplateRow = templateRow;
180	
181	        int rowIdx = startRowIndex;
182	        for (Map<Integer, Object> rowData : rows) {
183	            Row row = sheet.createRow(rowIdx++);
184	            rowData.forEach((colIdx, value) -> {
185	                Cell cell = row.createCell(colIdx);
186	
187	                if (finalTemplateRow != null) {
188	                    Cell templateCell = finalTemplateRow.getCell(colIdx);
189	                    if (templateCell != null) {
190	                        CellStyle style = styleCache.computeIfAbsent(colIdx, k -> {
191	                            CellStyle newStyle = workbook.createCellStyle();
192	                            newStyle.cloneStyleFrom(templateCell.getCellStyle());
193	                            return newStyle;
194	                        });
195	                        cell.setCellStyle(style);
196	                    }
197	                }
198	
199	                if (value instanceof Number) {
200	                    cell.setCellValue(((Number) value).doubleValue());
201	                } else if (value instanceof Boolean) {
202	                    cell.setCellValue((Boolean) value);
203	                } else if (value != null) {
204	                    cell.setCellValue(value.toString());
205	                }
206	            });
207	        }
208	
209	        try (FileOutputStream fos = new FileOutputStream(file)) {
210	                workbook.write(fos);
211	            }
212	        } finally {
213	            workbook.close();
214	        }
215	    }
216	
217	    /**
218	     * Normalizes the input value by trimming whitespace, or returns "INVALID" if the value
219	     * is null, empty, or matches a known invalid data marker.
220	     *
221	     * @param val the input value to validate
222	     * @return the trimmed string if valid, or "INVALID" if null/empty/invalid marker
223	     */
224	    public static String normalizeOrInvalid(Object val){
225	        if (val == null) return "INVALID";
226	        String str = val.toString().trim();
227	        if (str.isEmpty() || INVALID_VALUES.contains(str.toUpperCase())) {
228	            return "INVALID";
229	        }
230	        return str;
231	    }
232	
233	    // ==================== Private Helper Methods ====================
234	
235	    /**
236	     * Loads existing workbook or creates new one if file doesn't exist.
237	     */
238	    private static Workbook loadOrCreate(String targetFilePath) throws IOException {
239	        File file = new File(targetFilePath);
240	        if (file.exists() && file.length() > 0) {
241	            try (FileInputStream fis = new FileInputStream(file)) {
242	                return WorkbookFactory.create(fis);
243	            }
244	        }
245	        return new XSSFWorkbook();
246	    }
247	
248	    /**
249	     * Copies rows 0 to endRowIndex from sourceSheet to a new sheet in targetWorkbook.
250	     */
251	    private static void copySheetRows(Sheet sourceSheet, Workbook targetWorkbook,
252	                                      String targetSheetName, int endRowIndex) {
253	        Sheet targetSheet = targetWorkbook.createSheet(targetSheetName);
254	        copyColumnWidths(sourceSheet, targetSheet);
255	        targetSheet.setDefaultRowHeight(sourceSheet.getDefaultRowHeight());
256	
257	        Map<Integer, CellStyle> styleCache = new HashMap<>();
258	        int actualEnd = Math.min(endRowIndex, sourceSheet.getLastRowNum());
259	
260	        for (int rowIdx = 0; rowIdx <= actualEnd; rowIdx++) {
261	            Row srcRow = sourceSheet.getRow(rowIdx);
262	            if (srcRow == null) continue;
263	            Row dstRow = targetSheet.createRow(rowIdx);
264	            dstRow.setHeight(srcRow.getHeight());
265	            copyCells(srcRow, dstRow, targetWorkbook, styleCache);
266	        }
267	
268	        copyMergedRegions(sourceSheet, targetSheet, actualEnd);
269	    }
270	
271	    private static void copyCells(Row srcRow, Row dstRow,
272	                                  Workbook targetWb,
273	                                  Map<Integer, CellStyle> styleCache) {
274	        for (int col = srcRow.getFirstCellNum(); col < srcRow.getLastCellNum(); col++) {
275	            Cell src = srcRow.getCell(col);
276	            if (src == null) continue;
277	
278	            Cell dst = dstRow.createCell(col);
279	
280	            CellStyle style = styleCache.computeIfAbsent(
281	                    src.getCellStyle().hashCode(), k -> {
282	                        CellStyle s = targetWb.createCellStyle();
283	                        s.cloneStyleFrom(src.getCellStyle());
284	                        return s;
285	                    });
286	            dst.setCellStyle(style);
287	
288	            switch (src.getCellType()) {
289	                case STRING:
290	                    dst.setCellValue(src.getStringCellValue());
291	                    break;
292	                case NUMERIC:
293	                    if (DateUtil.isCellDateFormatted(src)) {
294	                        dst.setCellValue(src.getDateCellValue());
295	                    } else {
296	                        dst.setCellValue(src.getNumericCellValue());
297	                    }
298	                    break;
299	                case BOOLEAN:
300	                    dst.setCellValue(src.getBooleanCellValue());
301	                    break;
302	                case FORMULA:
303	                    dst.setCellFormula(src.getCellFormula());
304	                    break;
305	                case BLANK:
306	                    dst.setBlank();
307	                    break;
308	                case ERROR:
309	                    dst.setCellErrorValue(src.getErrorCellValue());
310	                    break;
311	                default:
312	                    break;
313	            }
314	        }
315	    }
316	
317	    private static void copyColumnWidths(Sheet src, Sheet dst) {
318	        int maxCol = 0;
319	        for (Row row : src) {
320	            if (row.getLastCellNum() > maxCol) maxCol = row.getLastCellNum();
321	        }
322	        dst.setDefaultColumnWidth(src.getDefaultColumnWidth());
323	        for (int i = 0; i < maxCol; i++) {
324	            dst.setColumnWidth(i, src.getColumnWidth(i));
325	        }
326	    }
327	
328	    private static void copyMergedRegions(Sheet src, Sheet dst, int endRow) {
329	        for (int i = 0; i < src.getNumMergedRegions(); i++) {
330	            CellRangeAddress region = src.getMergedRegion(i);
331	            if (region.getLastRow() <= endRow) {
332	                dst.addMergedRegion(region.copy());
333	            }
334	        }
335	    }
336	
337	    private static String getSheetNames(Workbook workbook) {
338	        StringBuilder sb = new StringBuilder("[");
339	        for (int i = 0; i < workbook.getNumberOfSheets(); i++) {
340	            if (i > 0) sb.append(", ");
341	            sb.append(workbook.getSheetName(i));
342	        }
343	        return sb.append("]").toString();
344	    }
345	}

